import numpy as np

def policy_iteration(num_states: int, num_actions: int, transitions: list, gamma: float, theta: float = 1e-8) -> tuple:
    # Initialize policy (all action 0) and value function (all zeros)
    policy = [0] * num_states
    values = [0.0] * num_states

    while True:
        # --- Phase 1: Policy Evaluation ---
        # Iteratively compute V(s) for the current policy until convergence
        while True:
            delta = 0.0
            for s in range(num_states):
                v_old = values[s]
                # Bellman expectation equation for current policy action
                v_new = 0.0
                for prob, next_s, reward in transitions[s][policy[s]]:
                    v_new += prob * (reward + gamma * values[next_s])
                values[s] = v_new
                delta = max(delta, abs(v_old - v_new))
            if delta < theta:
                break

        # --- Phase 2: Policy Improvement ---
        # Act greedily w.r.t. current value function
        policy_stable = True
        for s in range(num_states):
            old_action = policy[s]
            best_action = 0
            best_q = float('-inf')
            for a in range(num_actions):
                q = 0.0
                for prob, next_s, reward in transitions[s][a]:
                    q += prob * (reward + gamma * values[next_s])
                # Strict > ensures smallest-index tie-breaking
                if q > best_q:
                    best_q = q
                    best_action = a
            policy[s] = best_action
            if best_action != old_action:
                policy_stable = False

        if policy_stable:
            break

    return (policy, [round(v, 4) for v in values])
